export type WarehouseTypeValue = 'Material' | 'FinishedGoods' | 'Stage';

export const WAREHOUSE_TYPE_OPTIONS: { value: WarehouseTypeValue; label: string }[] = [
  { value: 'Material', label: 'Kho nguyên vật liệu' },
  { value: 'FinishedGoods', label: 'Kho thành phẩm' },
  { value: 'Stage', label: 'Kho bán thành phẩm' },
];

export function warehouseTypeLabel(value?: string): string {
  return WAREHOUSE_TYPE_OPTIONS.find(o => o.value === value)?.label ?? value ?? '—';
}
